import { Anthropic } from '@anthropic-ai/sdk';

const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });

const tools = [
  {
    name: 'process_payment',
    description: 'Process payment idempotently',
    inputSchema: {
      type: 'object',
      properties: {
        orderId: { type: 'string' },
        amount: { type: 'number' }
      }
    }
  },
  {
    name: 'rollback_order',
    description: 'Rollback failed workflow step',
    inputSchema: {
      type: 'object',
      properties: { orderId: { type: 'string' } }
    }
  }
] as const;

async function executeWorkflowWithApproval(client: Anthropic, orderId: string) {
  const msg = await client.messages.create({
    model: 'claude-3-5-sonnet-20240620',
    max_tokens: 1024,
    tools,
    messages: [{ role: 'user', content: `Order ${orderId} needs approval` }]
  });

  // Check if human approval requested
  const approvalTool = msg.content.find(c => c.type === 'tool_use' && c.name === 'request_human_approval');
  if (approvalTool) {
    const approved = await getHumanApproval(approvalTool.input.reason);
    if (!approved) throw new Error('Workflow rejected');
  }
}

