import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

async function safeToolExecution(toolUse: any) {
  const result = await vex.verify({
    spec: {
      actionCorrectness: true,
      permissionValidation: {
        required: ['order.process'],
        userContext: { userId: '123' }
      },
      idempotency: { orderId: toolUse.input.orderId },
      rollbackCapability: true
    },
    observation: toolUse,
    riskProfile: 'medium'
  });

  if (!result.passed) {
    console.error('Vex blocked:', result.issues);
    await executeRollback(toolUse.input.orderId);
    return null;
  }

  return await executeTool(toolUse);
}

